// ── Classify error type ──────────────────────────────────
const error = $input.first().json;
const errorMessage = error.execution?.error?.message || error.error?.message || 'Unknown error';
const workflowName = error.workflow?.name || 'Unknown Workflow';
const nodeName = error.execution?.lastNodeExecuted || 'Unknown Node';

// Extract ticket_id from the failed execution if available
let ticketId = null;
try {
  const execData = error.execution?.data?.resultData?.runData || {};
  const nodeKeys = Object.keys(execData);
  for (const key of nodeKeys) {
    const nodeData = execData[key]?.[0]?.data?.main?.[0]?.[0]?.json;
    if (nodeData?.ticket_id) {
      ticketId = nodeData.ticket_id;
      break;
    }
  }
} catch(e) { /* no ticket id found */ }

// Classify error type
let errorType = 'UNKNOWN_ERROR';
if (/timeout|ETIMEDOUT|ECONNABORTED/i.test(errorMessage))    errorType = 'API_TIMEOUT';
else if (/rate.?limit|429|too many requests/i.test(errorMessage)) errorType = 'RATE_LIMIT_ERROR';
else if (/postgres|ECONNREFUSED|database/i.test(errorMessage))   errorType = 'DATABASE_ERROR';
else if (/groq|openai|llm|classification/i.test(errorMessage))   errorType = 'AI_API_ERROR';
else if (/json|parse|invalid/i.test(errorMessage))               errorType = 'INVALID_AI_RESPONSE';
else if (/validation/i.test(errorMessage))                        errorType = 'VALIDATION_ERROR';

return [{
  json: {
    ticket_id:      ticketId,
    error_type:     errorType,
    error_message:  errorMessage,
    workflow_name:  workflowName,
    node_name:      nodeName,
    full_error:     JSON.stringify(error),
    timestamp:      new Date().toISOString(),
    should_retry:   ['API_TIMEOUT', 'RATE_LIMIT_ERROR', 'AI_API_ERROR'].includes(errorType)
  }
}];

// Terminal error — no retry possible
const d = $('Code: Classify Error').item.json;
console.log(`[ERROR HANDLER] Terminal failure for ticket ${d.ticket_id}: ${d.error_type} - ${d.error_message}`);
return [{ json: { ...d, terminal: true, message: 'Error logged. No retry scheduled.' } }];
